INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ário da República, 2.ª série, de 22 de março de 1997, 3712/2011, de 31 de janeiro, publicado no Diário da República, 2.ª série, de 25 de fevereiro de 2011, 9738/2015, de 19 de agosto, publicado no Diário da República, 2.ª série, de 26 de agosto de 2015, 3637/2018, de 28 de março, publicado no Diário da República, 2.ª série, de 11 de abril de 2018, e 7237/2023, de 15 de junho, publicado no Diário da República, 2.ª série, de 7 de julho de 2023; 
